import { DefineSetupFnComponent } from 'vue';
import { InertiaLinkProps, router } from '@inertiajs/vue3';
import { RouteName } from '@tuyau/client';
import { ValidatedApi, LinkParams } from '../types.js';

declare const TUYAU_PLUGIN = "TUYAU_PLUGIN";
declare function getClientKey(key?: string): string;
declare const TuyauPlugin: {
    install: (app: any, options: {
        client: {
            $url: any;
        };
    }) => void;
};
/**
 * We need to do weird things here to make it work. If defining the component the standard way,
 * Typescript will resolve the generic and replace it with a `never` at build time. So
 * kind of unusable.
 */
type LinkComponentType<T extends RouteName<ValidatedApi['routes']>> = DefineSetupFnComponent<LinkParams<T> & Omit<InertiaLinkProps, 'href' | 'method'>>;
declare const Link: <Route extends RouteName<ValidatedApi['routes']>>(props: LinkParams<Route> & Omit<InertiaLinkProps, 'href' | 'method'>) => LinkComponentType<Route>;
declare function useRouter(): {
    visit: <Route extends RouteName<ValidatedApi["routes"]>>(props: LinkParams<Route> & Omit<InertiaLinkProps, "href" | "method">, options?: Parameters<typeof router.visit>[1]) => any;
};

export { Link, TUYAU_PLUGIN, TuyauPlugin, getClientKey, useRouter };
